## Schritt 5 — UI: Compound-Beschreibung im Rules-Modal

**Datei:** `apps/web/src/components/format-workspace/rules-list-modal.tsx`
**Testdatei:** (keine eigene Testdatei — wird über bestehende Component-Tests abgedeckt)

### Änderungen

`describeSelectorStrategy` (Zeile 97-126) um `case "compound":` erweitern:

```ts
case "compound": {
  const parts: string[] = [];

  if (blockType) parts.push(blockType);

  const role = typeof s.messageRole === "string" ? s.messageRole : null;
  if (role) parts.push(`Rolle: ${role}`);

  const level = typeof s.headingLevel === "number" ? s.headingLevel : null;
  if (level) parts.push(`H${level}`);

  const pos = typeof s.position === "string" ? s.position : null;
  if (pos) parts.push(pos === "first" ? "Erster Block" : "Letzter Block");

  const pattern = typeof s.textPattern === "string" ? s.textPattern : null;
  if (pattern) parts.push(`Pattern: "${pattern}"`);

  const ctx = s.context && typeof s.context === "object" ? s.context as Record<string, unknown> : null;
  if (ctx?.previousSibling) parts.push("nach bestimmtem Block");
  if (ctx?.nextSibling) parts.push("vor bestimmtem Block");

  return parts.length > 0
    ? `Compound: ${parts.join(", ")}`
    : "Compound-Filter (alle Blöcke)";
}
```

### Erfolgskriterien

- [x] Compound-Selektoren werden menschenlesbar im Modal angezeigt
- [x] Bestehende Strategien unverändert
